/*
 * 2019 성균관대 인문계 기출문제 원본 완본 뷰어
 * OCR/재조판 없이 원본 PDF 바이트를 그대로 브라우저 PDF 렌더러에 전달합니다.
 */
(function installSkku2019OriginalViewer() {
  'use strict';

  const PDF_BASE64 = '';
  let viewerMode = 'original';
  let objectUrl = '';

  function getPdfUrl() {
    if (objectUrl) return objectUrl;
    const binary = atob(PDF_BASE64);
    const bytes = new Uint8Array(binary.length);
    for (let i = 0; i < binary.length; i += 1) bytes[i] = binary.charCodeAt(i);
    objectUrl = URL.createObjectURL(new Blob([bytes], { type: 'application/pdf' }));
    return objectUrl;
  }

  function buttonStyle(active) {
    return [
      'min-height:36px',
      'padding:6px 12px',
      'border:1px solid var(--line)',
      'border-radius:2px',
      active ? 'background:var(--ink)' : 'background:transparent',
      active ? 'color:#fff' : 'color:var(--ink)',
      'font:inherit',
      'font-weight:700',
      'cursor:pointer'
    ].join(';');
  }

  function renderOriginal(baseRender) {
    const target = document.getElementById('examContent');
    if (!target) return;

    const pdfUrl = getPdfUrl();
    target.innerHTML = `
      <div class="skku-original-viewer" style="max-width:1100px;margin:0 auto">
        <div style="display:flex;flex-wrap:wrap;gap:8px;align-items:center;margin-bottom:12px">
          <button type="button" id="skku2019OriginalBtn" style="${buttonStyle(true)}">원본 완본</button>
          <button type="button" id="skku2019QuizBtn" style="${buttonStyle(false)}">문제풀이</button>
          <a href="${pdfUrl}" target="_blank" rel="noopener"
             style="margin-left:auto;font-size:13px;color:var(--accent)">새 창에서 원본 열기</a>
        </div>
        <p style="margin:0 0 10px;font-size:12px;color:var(--muted)">
          OCR이나 재조판이 아니라 업로드된 2019학년도 성균관대 인문계 시험지 PDF 원본을 직접 표시합니다.
        </p>
        <iframe
          title="2019학년도 성균관대 인문계 기출문제 원본"
          src="${pdfUrl}#view=FitH&toolbar=1&navpanes=0"
          style="display:block;width:100%;height:min(82vh,1100px);min-height:680px;border:1px solid var(--line);background:#777"
          loading="eager">
        </iframe>
      </div>`;

    document.getElementById('skku2019OriginalBtn').onclick = function () {
      viewerMode = 'original';
      window.renderExamTab();
    };
    document.getElementById('skku2019QuizBtn').onclick = function () {
      viewerMode = 'quiz';
      baseRender();
      addOriginalButton();
    };
  }

  function addOriginalButton() {
    if (window.examTab !== 'skku2019') return;
    const target = document.getElementById('examContent');
    if (!target || document.getElementById('skku2019BackToOriginal')) return;

    const bar = document.createElement('div');
    bar.style.cssText = 'max-width:700px;margin:0 auto 12px;display:flex;gap:8px';
    bar.innerHTML =
      '<button type="button" id="skku2019BackToOriginal" style="' +
      buttonStyle(true) +
      '">원본 완본 보기</button>';
    target.insertBefore(bar, target.firstChild);

    document.getElementById('skku2019BackToOriginal').onclick = function () {
      viewerMode = 'original';
      window.renderExamTab();
    };
  }

  function patchRenderExamTab() {
    if (typeof window.renderExamTab !== 'function') return false;
    if (window.renderExamTab.__skku2019OriginalPatched) return true;

    const baseRender = window.renderExamTab;

    function patchedRenderExamTab() {
      if (window.examTab === 'skku2019' && viewerMode === 'original') {
        renderOriginal(baseRender);
        return;
      }
      baseRender();
      addOriginalButton();
    }

    patchedRenderExamTab.__skku2019OriginalPatched = true;
    window.renderExamTab = patchedRenderExamTab;
    return true;
  }

  document.addEventListener('DOMContentLoaded', function () {
    if (patchRenderExamTab()) return;
    let attempts = 0;
    const timer = setInterval(function () {
      attempts += 1;
      if (patchRenderExamTab() || attempts >= 50) clearInterval(timer);
    }, 100);
  });

  window.addEventListener('beforeunload', function () {
    if (objectUrl) URL.revokeObjectURL(objectUrl);
  });
})();
